module RefModule (
    input [3:0] in0,
    input [3:0] in1,
    input sel,
    output reg [3:0] out
);
  wire [3:0] _tap_in0 = in0 & {4{1'b1}};


always @(*) begin
    case (sel)
        1'b0: out = in0;
        1'b1: out = in1;
        default: out = 4'b0000; // Default case for safety
    endcase
end

endmodule
